/**
 * FinSuite OS - Car Loan EMI Calculator
 */
import { calculateEMI, formatCurrency } from '@/core/math';
import { SmartChart } from '@/components/charts/SmartChart';
import { createSmartInput, createResultCard } from '@/components/ui/SmartInput';

export function render(): HTMLElement {
  const state = { principal: 800000, rate: 9, tenure: 60 };
  const container = document.createElement('div');
  container.innerHTML = `
    <header class="page-header"><h1 class="page-title">≡ƒÜù Car Loan EMI</h1><p class="page-subtitle">Calculate your car loan EMI</p></header>
    <div class="calculator-layout">
      <div class="calculator-inputs glass-card" style="padding: var(--space-6);" id="inputs"></div>
      <div class="calculator-results" id="results"></div>
    </div>
  `;
  const inputs = container.querySelector('#inputs') as HTMLElement;
  const results = container.querySelector('#results') as HTMLElement;
  let chart: SmartChart | null = null;

  function update(): void {
    const result = calculateEMI(state.principal, state.rate, state.tenure);
    results.innerHTML = '';
    const stats = document.createElement('div');
    stats.className = 'stats-grid mb-6';
    stats.appendChild(
      createResultCard({ label: 'Monthly EMI', value: formatCurrency(result.emi), accent: true })
    );
    stats.appendChild(
      createResultCard({ label: 'Total Interest', value: formatCurrency(result.totalInterest) })
    );
    stats.appendChild(
      createResultCard({ label: 'Total Payment', value: formatCurrency(result.totalPayment) })
    );
    results.appendChild(stats);

    const chartBox = document.createElement('div');
    chartBox.className = 'chart-container';
    const canvas = document.createElement('canvas');
    chartBox.appendChild(canvas);
    results.appendChild(chartBox);
    if (chart) chart.destroy();
    chart = new SmartChart(canvas);
    chart.render({
      type: 'doughnut',
      labels: ['Principal', 'Interest'],
      datasets: [{ label: 'Amount', data: [state.principal, result.totalInterest] }],
    });
  }

  inputs.innerHTML = '<h3 style="margin-bottom: var(--space-4);">Loan Details</h3>';
  inputs.appendChild(
    createSmartInput({
      id: 'prin',
      label: 'Car Price / Loan Amount',
      min: 100000,
      max: 10000000,
      value: state.principal,
      step: 50000,
      prefix: 'Γé╣',
      currency: true,
      onChange: (v) => {
        state.principal = v;
        update();
      },
    })
  );
  const r = document.createElement('div');
  r.style.marginTop = 'var(--space-6)';
  r.appendChild(
    createSmartInput({
      id: 'rate',
      label: 'Interest Rate',
      min: 1,
      max: 50,
      value: state.rate,
      step: 0.1,
      suffix: '%',
      onChange: (v) => {
        state.rate = v;
        update();
      },
    })
  );
  inputs.appendChild(r);
  const t = document.createElement('div');
  t.style.marginTop = 'var(--space-6)';
  t.appendChild(
    createSmartInput({
      id: 'tenure',
      label: 'Tenure (Months)',
      min: 12,
      max: 84,
      value: state.tenure,
      step: 12,
      onChange: (v) => {
        state.tenure = v;
        update();
      },
    })
  );
  inputs.appendChild(t);
  update();
  return container;
}

/**
 * FinSuite OS - FD Calculator
 */
import { calculateFD, formatCurrency } from '@/core/math';
import { createSmartInput, createResultCard, createSelect } from '@/components/ui/SmartInput';

export function render(): HTMLElement {
  const state = { principal: 100000, rate: 7, tenure: 12, freq: 4 };
  const container = document.createElement('div');
  container.innerHTML = `
    <header class="page-header"><h1 class="page-title">≡ƒÅª FD Calculator</h1><p class="page-subtitle">Fixed Deposit maturity amount</p></header>
    <div class="calculator-layout">
      <div class="calculator-inputs glass-card" style="padding: var(--space-6);" id="inputs"></div>
      <div class="calculator-results" id="results"></div>
    </div>
  `;
  const inputs = container.querySelector('#inputs') as HTMLElement;
  const results = container.querySelector('#results') as HTMLElement;

  function update(): void {
    const result = calculateFD(state.principal, state.rate, state.tenure, state.freq);
    results.innerHTML = '';
    const stats = document.createElement('div');
    stats.className = 'stats-grid';
    stats.appendChild(
      createResultCard({
        label: 'Maturity Amount',
        value: formatCurrency(result.maturityAmount),
        accent: true,
      })
    );
    stats.appendChild(
      createResultCard({ label: 'Interest Earned', value: formatCurrency(result.totalInterest) })
    );
    stats.appendChild(
      createResultCard({ label: 'Effective Yield', value: `${result.effectiveYield}% p.a.` })
    );
    results.appendChild(stats);
  }

  inputs.innerHTML = '<h3 style="margin-bottom: var(--space-4);">FD Details</h3>';
  inputs.appendChild(
    createSmartInput({
      id: 'prin',
      label: 'Deposit Amount',
      min: 1000,
      max: 10000000,
      value: state.principal,
      step: 10000,
      prefix: 'Γé╣',
      currency: true,
      onChange: (v) => {
        state.principal = v;
        update();
      },
    })
  );
  const r = document.createElement('div');
  r.style.marginTop = 'var(--space-6)';
  r.appendChild(
    createSmartInput({
      id: 'rate',
      label: 'Interest Rate',
      min: 1,
      max: 50,
      value: state.rate,
      step: 0.1,
      suffix: '%',
      onChange: (v) => {
        state.rate = v;
        update();
      },
    })
  );
  inputs.appendChild(r);
  const t = document.createElement('div');
  t.style.marginTop = 'var(--space-6)';
  t.appendChild(
    createSmartInput({
      id: 'tenure',
      label: 'Tenure (Months)',
      min: 1,
      max: 120,
      value: state.tenure,
      onChange: (v) => {
        state.tenure = v;
        update();
      },
    })
  );
  inputs.appendChild(t);
  const f = document.createElement('div');
  f.style.marginTop = 'var(--space-6)';
  f.appendChild(
    createSelect({
      id: 'freq',
      label: 'Compounding Frequency',
      value: String(state.freq),
      options: [
        { value: '1', label: 'Yearly' },
        { value: '2', label: 'Half-Yearly' },
        { value: '4', label: 'Quarterly' },
        { value: '12', label: 'Monthly' },
      ],
      onChange: (v) => {
        state.freq = parseInt(v);
        update();
      },
    })
  );
  inputs.appendChild(f);
  update();
  return container;
}

/**
 * FinSuite OS - Home Loan EMI Calculator
 */
import { calculateEMI, formatCurrency, formatIndianNumber } from '@/core/math';
import { askAI } from '@/core/puter';
import { SmartChart } from '@/components/charts/SmartChart';
import {
  createSmartInput,
  createResultCard,
  createAIInsight,
  updateAIInsight,
} from '@/components/ui/SmartInput';

export function render(): HTMLElement {
  const state = { principal: 5000000, rate: 8.5, tenure: 240 };
  const container = document.createElement('div');
  container.innerHTML = `
    <header class="page-header"><h1 class="page-title">≡ƒÅá Home Loan EMI</h1><p class="page-subtitle">Calculate your home loan EMI & amortization</p></header>
    <div class="calculator-layout">
      <div class="calculator-inputs glass-card" style="padding: var(--space-6);" id="inputs"></div>
      <div class="calculator-results" id="results"></div>
    </div>
  `;
  const inputs = container.querySelector('#inputs') as HTMLElement;
  const results = container.querySelector('#results') as HTMLElement;
  let chart: SmartChart | null = null;

  function update(): void {
    const result = calculateEMI(state.principal, state.rate, state.tenure);
    results.innerHTML = '';

    const stats = document.createElement('div');
    stats.className = 'stats-grid mb-6';
    stats.appendChild(
      createResultCard({ label: 'Monthly EMI', value: formatCurrency(result.emi), accent: true })
    );
    stats.appendChild(
      createResultCard({
        label: 'Total Interest',
        value: formatCurrency(result.totalInterest),
        subtext: `${result.interestPercent}% of total`,
      })
    );
    stats.appendChild(
      createResultCard({ label: 'Total Payment', value: formatCurrency(result.totalPayment) })
    );
    results.appendChild(stats);

    // Pie chart for breakdown
    const chartBox = document.createElement('div');
    chartBox.className = 'chart-container mb-6';
    const canvas = document.createElement('canvas');
    chartBox.appendChild(canvas);
    results.appendChild(chartBox);
    if (chart) chart.destroy();
    chart = new SmartChart(canvas);
    chart.render({
      type: 'doughnut',
      labels: ['Principal', 'Interest'],
      datasets: [{ label: 'Amount', data: [state.principal, result.totalInterest] }],
      title: 'Principal vs Interest',
    });

    const aiBox = createAIInsight('', true);
    results.appendChild(aiBox);
    askAI(
      `Home loan: Γé╣${formatIndianNumber(state.principal)} at ${state.rate}% for ${state.tenure / 12} years. EMI: Γé╣${formatIndianNumber(result.emi)}. Interest: Γé╣${formatIndianNumber(result.totalInterest)}. Suggest prepayment strategy.`,
      'strategist'
    )
      .then((i) => updateAIInsight(aiBox, i))
      .catch(() => updateAIInsight(aiBox, 'AI unavailable'));
  }

  inputs.innerHTML = '<h3 style="margin-bottom: var(--space-4);">Loan Details</h3>';
  inputs.appendChild(
    createSmartInput({
      id: 'prin',
      label: 'Loan Amount',
      min: 100000,
      max: 100000000,
      value: state.principal,
      step: 100000,
      prefix: 'Γé╣',
      currency: true,
      onChange: (v) => {
        state.principal = v;
        update();
      },
    })
  );
  const r = document.createElement('div');
  r.style.marginTop = 'var(--space-6)';
  r.appendChild(
    createSmartInput({
      id: 'rate',
      label: 'Interest Rate',
      min: 1,
      max: 50,
      value: state.rate,
      step: 0.1,
      suffix: '%',
      onChange: (v) => {
        state.rate = v;
        update();
      },
    })
  );
  inputs.appendChild(r);
  const t = document.createElement('div');
  t.style.marginTop = 'var(--space-6)';
  t.appendChild(
    createSmartInput({
      id: 'tenure',
      label: 'Tenure (Months)',
      min: 12,
      max: 360,
      value: state.tenure,
      step: 12,
      suffix: ` mo (${state.tenure / 12} yrs)`,
      onChange: (v) => {
        state.tenure = v;
        update();
      },
    })
  );
  inputs.appendChild(t);
  update();
  return container;
}

/**
 * FinSuite OS - Inflation Calculator
 */
import { calculateInflation, calculatePresentValue, formatCurrency } from '@/core/math';
import { createSmartInput, createResultCard, createToggle } from '@/components/ui/SmartInput';

export function render(): HTMLElement {
  const state = { amount: 100000, rate: 6, years: 10, reverse: false };
  const container = document.createElement('div');
  container.innerHTML = `
    <header class="page-header"><h1 class="page-title">≡ƒôê Inflation Calculator</h1><p class="page-subtitle">Purchasing power over time</p></header>
    <div class="calculator-layout">
      <div class="calculator-inputs glass-card" style="padding: var(--space-6);" id="inputs"></div>
      <div class="calculator-results" id="results"></div>
    </div>
  `;
  const inputs = container.querySelector('#inputs') as HTMLElement;
  const results = container.querySelector('#results') as HTMLElement;

  function update(): void {
    results.innerHTML = '';
    if (state.reverse) {
      const present = calculatePresentValue(state.amount, state.rate, state.years);
      const stats = document.createElement('div');
      stats.className = 'stats-grid';
      stats.appendChild(
        createResultCard({
          label: `Future Value (in ${state.years} yrs)`,
          value: formatCurrency(state.amount),
        })
      );
      stats.appendChild(
        createResultCard({ label: "Today's Value", value: formatCurrency(present), accent: true })
      );
      stats.appendChild(
        createResultCard({
          label: 'Loss in Value',
          value: formatCurrency(state.amount - present),
          subtext: `${(((state.amount - present) / state.amount) * 100).toFixed(1)}% decrease`,
        })
      );
      results.appendChild(stats);
    } else {
      const future = calculateInflation(state.amount, state.rate, state.years);
      const stats = document.createElement('div');
      stats.className = 'stats-grid';
      stats.appendChild(
        createResultCard({ label: "Today's Amount", value: formatCurrency(state.amount) })
      );
      stats.appendChild(
        createResultCard({
          label: `Future Cost (in ${state.years} yrs)`,
          value: formatCurrency(future),
          accent: true,
        })
      );
      stats.appendChild(
        createResultCard({
          label: 'Increase',
          value: formatCurrency(future - state.amount),
          subtext: `${(((future - state.amount) / state.amount) * 100).toFixed(1)}% increase`,
        })
      );
      results.appendChild(stats);
    }
  }

  inputs.innerHTML = '<h3 style="margin-bottom: var(--space-4);">Calculate Inflation Impact</h3>';
  inputs.appendChild(
    createSmartInput({
      id: 'amt',
      label: 'Amount',
      min: 1000,
      max: 100000000,
      value: state.amount,
      step: 10000,
      prefix: 'Γé╣',
      currency: true,
      onChange: (v) => {
        state.amount = v;
        update();
      },
    })
  );
  const r = document.createElement('div');
  r.style.marginTop = 'var(--space-6)';
  r.appendChild(
    createSmartInput({
      id: 'rate',
      label: 'Inflation Rate',
      min: 1,
      max: 50,
      value: state.rate,
      step: 0.5,
      suffix: '%',
      onChange: (v) => {
        state.rate = v;
        update();
      },
    })
  );
  inputs.appendChild(r);
  const y = document.createElement('div');
  y.style.marginTop = 'var(--space-6)';
  y.appendChild(
    createSmartInput({
      id: 'years',
      label: 'Time Period',
      min: 1,
      max: 50,
      value: state.years,
      suffix: ' years',
      onChange: (v) => {
        state.years = v;
        update();
      },
    })
  );
  inputs.appendChild(y);
  const t = document.createElement('div');
  t.style.marginTop = 'var(--space-6)';
  t.appendChild(
    createToggle({
      id: 'rev',
      label: 'Reverse (Future ΓåÆ Today)',
      checked: state.reverse,
      onChange: (v) => {
        state.reverse = v;
        update();
      },
    })
  );
  inputs.appendChild(t);
  update();
  return container;
}

/**
