              <td style="padding: var(--space-3); text-align: right; font-family: var(--font-mono); color: ${c.price_change_percentage_24h >= 0 ? 'var(--accent-growth)' : 'var(--accent-cost)'};">
                ${c.price_change_percentage_24h >= 0 ? 'Γû▓' : 'Γû╝'} ${Math.abs(c.price_change_percentage_24h).toFixed(2)}%
              </td>
              <td style="padding: var(--space-3); text-align: right; font-family: var(--font-mono);">Γé╣${formatLargeNumber(c.market_cap)}</td>
              <td style="padding: var(--space-3); text-align: right; font-family: var(--font-mono);">Γé╣${formatLargeNumber(c.total_volume)}</td>
            </tr>
          `
            )
            .join('')}
        </tbody>
      </table>
    </div>
    <p style="margin-top: var(--space-4); font-size: var(--text-xs); color: var(--text-tertiary); text-align: center;">Data from CoinGecko API ΓÇó Prices in INR</p>
  `;
}

function formatLargeNumber(num: number): string {
  if (num >= 10000000000000) return `${(num / 10000000000000).toFixed(1)}T`;
  if (num >= 1000000000) return `${(num / 1000000000).toFixed(1)}B`;
  if (num >= 10000000) return `${(num / 10000000).toFixed(1)}Cr`;
  if (num >= 100000) return `${(num / 100000).toFixed(1)}L`;
  return num.toLocaleString('en-IN');
}

