                <div style="font-weight: 600; color: var(--text-primary); margin-bottom: var(--space-2);">${w.title}</div>
                <p style="font-size: var(--text-sm); color: var(--text-secondary);">${w.snippet.replace(/<[^>]*>/g, '').slice(0, 150)}...</p>
