// Default route
const DEFAULT_ROUTE = '/system/dashboard';

class Router {
  private currentPath: string = '';
  private contentContainer: HTMLElement | null = null;
  private listeners: Array<(path: string) => void> = [];

  /**
   * Initialize the router
   */
  init(container: HTMLElement): void {
    this.contentContainer = container;

    // Handle browser back/forward
    window.addEventListener('popstate', () => {
      this.navigate(window.location.pathname, false);
    });

    // Handle initial route
    const path = window.location.pathname || DEFAULT_ROUTE;
    this.navigate(path, false);
  }

  /**
   * Navigate to a path
   */
  async navigate(path: string, pushState = true): Promise<void> {
    // Normalize path
    const normalizedPath = path === '/' ? DEFAULT_ROUTE : path;

    // Find matching route
    const route = this.findRoute(normalizedPath);

    if (!route) {
      console.warn(`Route not found: ${normalizedPath}`);
      await this.navigate(DEFAULT_ROUTE, false);
      return;
    }

    // Update browser history
    if (pushState && this.currentPath !== normalizedPath) {
      window.history.pushState({}, '', normalizedPath);
    }

    this.currentPath = normalizedPath;

    // Update SEO meta tags
    updateSEO(route.seo);

    // Notify listeners
    this.listeners.forEach((fn) => fn(normalizedPath));

    // Load and render component
    if (this.contentContainer) {
      this.contentContainer.innerHTML =
        '<div class="flex items-center justify-center" style="min-height: 400px;"><div class="spinner"></div></div>';

      try {
        const element = await route.component();
        this.contentContainer.innerHTML = '';
        this.contentContainer.appendChild(element);
      } catch (error) {
        console.error('Route load error:', error);
        this.contentContainer.innerHTML = `
          <div class="glass-card" style="padding: var(--space-8); text-align: center;">
            <h2 style="color: var(--accent-cost); margin-bottom: var(--space-4);">Failed to load</h2>
            <p style="color: var(--text-secondary);">Unable to load this app. Please try again.</p>
            <button class="btn btn--primary mt-6" onclick="window.router.navigate('/system/dashboard')">
              Go to Dashboard
            </button>
          </div>
        `;
      }
    }
  }

  /**
   * Find a route by path
   */
  findRoute(path: string): Route | undefined {
    return routes.find((r) => r.path === path);
  }

  /**
   * Get routes by drive
   */
  getRoutesByDrive(drive: Route['drive']): Route[] {
    return routes.filter((r) => r.drive === drive);
  }

  /**
   * Get current path
   */
  getCurrentPath(): string {
    return this.currentPath;
  }

  /**
   * Subscribe to route changes
   */
  onNavigate(callback: (path: string) => void): () => void {
    this.listeners.push(callback);
    return () => {
      this.listeners = this.listeners.filter((fn) => fn !== callback);
    };
  }
}

// Singleton instance
export const router = new Router();

// Make router globally available for onclick handlers
declare global {
  interface Window {
    router: Router;
  }
}
window.router = router;

/**
 * FinSuite OS - SEO Manager
 * Dynamic meta tag management for SPA
 */

export interface SEOConfig {
  title: string;
  description: string;
  keywords: string[];
  ogImage?: string;
  ogType?: string;
  canonical?: string;
}

const SITE_NAME = 'FinSuite OS';
const DEFAULT_OG_IMAGE = '/og-image.png';
const BASE_URL = 'https://money.chirag127.in';

/**
 * Update all SEO-related meta tags
 */
export function updateSEO(config: SEOConfig): void {
  const { title, description, keywords, ogImage, ogType = 'website', canonical } = config;

  // Update document title
  document.title = `${title} | ${SITE_NAME}`;

  // Helper to update or create meta tag
  const setMeta = (name: string, content: string, property = false): void => {
    const attr = property ? 'property' : 'name';
    let meta = document.querySelector(`meta[${attr}="${name}"]`) as HTMLMetaElement;
    if (!meta) {
      meta = document.createElement('meta');
      meta.setAttribute(attr, name);
      document.head.appendChild(meta);
    }
    meta.content = content;
  };

  // Standard meta tags
  setMeta('description', description);
  setMeta('keywords', keywords.join(', '));
  setMeta('author', 'FinSuite OS');
  setMeta('robots', 'index, follow');

  // Open Graph tags
  setMeta('og:title', `${title} | ${SITE_NAME}`, true);
  setMeta('og:description', description, true);
  setMeta('og:type', ogType, true);
  setMeta('og:image', ogImage || DEFAULT_OG_IMAGE, true);
  setMeta('og:site_name', SITE_NAME, true);
  setMeta('og:url', canonical || `${BASE_URL}${window.location.pathname}`, true);

  // Twitter Card tags
  setMeta('twitter:card', 'summary_large_image');
  setMeta('twitter:title', `${title} | ${SITE_NAME}`);
  setMeta('twitter:description', description);
  setMeta('twitter:image', ogImage || DEFAULT_OG_IMAGE);

  // Canonical URL
  let link = document.querySelector('link[rel="canonical"]') as HTMLLinkElement;
  if (!link) {
    link = document.createElement('link');
    link.rel = 'canonical';
    document.head.appendChild(link);
  }
  link.href = canonical || `${BASE_URL}${window.location.pathname}`;
}

/**
 * Generate JSON-LD structured data for a calculator page
 */
export function addStructuredData(
  type: 'Calculator' | 'WebApplication' | 'Article',
  data: Record<string, unknown>
): void {
  // Remove existing structured data
  document.querySelectorAll('script[type="application/ld+json"]').forEach((el) => el.remove());

  const script = document.createElement('script');
  script.type = 'application/ld+json';

  const baseData = {
    '@context': 'https://schema.org',
    '@type': type,
    ...data,
  };

  script.textContent = JSON.stringify(baseData);
  document.head.appendChild(script);
}

